// ==================== HALL ====================
// derives the player's next suggested step from current state — guides the first loop, then retires itself
function nextStep(state){
  if(state.adventurers.length===0) return { tab:"advs", icon:"⚔️", txt:"Hire your first adventurer from the Recruitment Board.", cta:"Recruit" };
  if(state.quests.length===0 && state.crafting.length===0 && Object.values(state.inventory).reduce((a,b)=>a+b,0)===0)
    return { tab:"quests", icon:"🗺️", txt:"Send an adventurer on an expedition to gather loot.", cta:"Dispatch" };
  const hasRaw = Object.entries(state.inventory).some(([k,v])=>v>0 && ITEMS[k] && ITEMS[k].tier!=="fin");
  const hasGoods = Object.entries(state.inventory).some(([k,v])=>v>0 && ITEMS[k] && ITEMS[k].tier==="fin");
  if(hasRaw && state.crafting.length===0 && !hasGoods)
    return { tab:"craft", icon:"⚒️", txt:"Craft your loot into goods worth more at market.", cta:"Craft" };
  if(hasGoods) return { tab:"market", icon:"💰", txt:"Sell your finished goods at the Market for gold.", cta:"Sell" };
  return null; // player has completed the core loop — guidance retires
}

